insert into offmarket.business_signals (business_id, layer, signal_key, direction, weight, evidence, source, source_url, observed_at) values
('8ee3288a-0589-5152-9905-1fdb21f2e567', 4, 'low_pe_attention_vertical', 'positive', NULL, 'TX land surveying = LOW-PE-ATTENTION vertical. Only Bowman Consulting (NASDAQ:BWMN) + Westwood Professional Services (Endeavour Capital) are PE-backed rollup platforms active in TX surveying. Large-AEC strategics (Stantec/WSP/AECOM/Kimley-Horn/Cobb Fendley/LJA) only bolt-on $5M+ rev firms. Sub-$5M independent universe (Houston, Harris County) structurally under-targeted = opportunity zone. ETA/search-fund appetite emerging fast 2024-2026 per Stanford Search Fund Study (top-15 ETA vertical).', 'verticals.md skill config + Stanford Search Fund Study + Bowman 10-K filings', 'https://pels.texas.gov/roster/ls_rosters.html', '2026-05-16'),
('8ee3288a-0589-5152-9905-1fdb21f2e567', 2, 'distress', 'disqualifying', NULL, 'Comptroller franchise-tax status: verification_needed - BuildZoom flags inactive but firm still on TBPELS roster as ''Registered''', 'enrichment', NULL, '2026-05-16'),
