('08a9211e-bdda-553c-82c8-9334bda0bf83', 2, 'firm_tenure_long', 'positive', NULL, 'Senior RPLS James Walton Griffith tenure 50yr per TBPELS RPLS roster. Firm registered as TBPELS Surveying Firm #10169900 since 2009-09-02. Passes >5yr settled-business hard gate.', 'tbpels_surveying_firms_roster', 'https://tbpedownloads.s3-us-west-2.amazonaws.com/sur-firm_roster.csv', '2026-05-16'),
('08a9211e-bdda-553c-82c8-9334bda0bf83', 2, 'rpls_license_skilled_trade_moat', 'positive', NULL, 'TX RPLS license = 4yr ABET-accredited surveying or equivalent + 4yr supervised survey-in-training + Tex. Occ. Code Ch. 1071 state exam. ~3,700 active RPLS statewide (TBPELS roster May 2026). Workforce documented as aging (TSPS workforce-shortage reports cite avg RPLS age >55).', 'tbpels_rpls_roster_aggregate', 'https://pels.texas.gov/roster/ls_rosters.html', '2026-05-16'),
('08a9211e-bdda-553c-82c8-9334bda0bf83', 3, 'solo_rpls_no_successor', 'positive', NULL, 'TBPELS firm roster + RPLS cross-reference shows exactly 1 active RPLS at firm #10169900 (James Walton Griffith) — no second RPLS added in 50yr tenure. No credentialed internal successor visible at the license-board level. NOTE: live team-page fetch required before A-tier promotion per skill non-negotiable.', 'tbpels_firm_rpls_join', 'https://tbpedownloads.s3-us-west-2.amazonaws.com/rpls_roster.csv', '2026-05-16'),
